import { format, formatDistanceToNow } from 'date-fns';

/**
 * Formats a date string or Date object into a user-friendly format
 * 
 * @param {string|Date} dateInput - The date to format
 * @param {Object} options - Additional formatting options
 * @param {boolean} options.includeTime - Whether to include the time
 * @param {boolean} options.relative - Whether to use relative time (e.g., "2 days ago")
 * @returns {string} The formatted date string
 */
const formatDate = (dateInput, options = {}) => {
  if (!dateInput) return '';
  
  const date = new Date(dateInput);
  
  // Return invalid date message if the date is invalid
  if (isNaN(date.getTime())) {
    return 'Invalid date';
  }
  
  const { includeTime = false, relative = true } = options;
  
  // For relative dates
  if (relative) {
    const rtf = new Intl.RelativeTimeFormat('en', { numeric: 'auto' });
    const now = new Date();
    const diffInSeconds = Math.floor((now - date) / 1000);
    
    // Less than a minute ago
    if (diffInSeconds < 60) {
      return 'just now';
    }
    
    // Less than an hour ago
    if (diffInSeconds < 3600) {
      const minutes = Math.floor(diffInSeconds / 60);
      return rtf.format(-minutes, 'minute');
    }
    
    // Less than a day ago
    if (diffInSeconds < 86400) {
      const hours = Math.floor(diffInSeconds / 3600);
      return rtf.format(-hours, 'hour');
    }
    
    // Less than a week ago
    if (diffInSeconds < 604800) {
      const days = Math.floor(diffInSeconds / 86400);
      return rtf.format(-days, 'day');
    }
    
    // Less than a month ago
    if (diffInSeconds < 2592000) {
      const weeks = Math.floor(diffInSeconds / 604800);
      return rtf.format(-weeks, 'week');
    }
    
    // Less than a year ago
    if (diffInSeconds < 31536000) {
      const months = Math.floor(diffInSeconds / 2592000);
      return rtf.format(-months, 'month');
    }
    
    // More than a year ago
    const years = Math.floor(diffInSeconds / 31536000);
    return rtf.format(-years, 'year');
  }
  
  // Fallback to standard date format
  const dateFormatOptions = {
    year: 'numeric',
    month: 'short',
    day: 'numeric',
    ...(includeTime ? { hour: '2-digit', minute: '2-digit' } : {})
  };
  
  return new Intl.DateTimeFormat('en-US', dateFormatOptions).format(date);
};

/**
 * Format a date with both date and time
 * @param {string|Date} date - Date to format
 * @returns {string} Formatted date and time
 */
const formatDateTime = (date) => {
  if (!date) return 'N/A';
  
  try {
    const dateObj = new Date(date);
    return format(dateObj, 'PPp'); // Mar 15, 2023, 3:45 PM
  } catch (error) {
    console.error('Error formatting date and time:', error);
    return 'Invalid date';
  }
};

/**
 * Format a date as relative time (e.g., "5 days ago")
 * @param {string|Date} date - Date to format
 * @returns {string} Relative time
 */
const formatRelativeTime = (date) => {
  if (!date) return 'N/A';
  
  try {
    const dateObj = new Date(date);
    return formatDistanceToNow(dateObj, { addSuffix: true });
  } catch (error) {
    console.error('Error formatting relative time:', error);
    return 'Invalid date';
  }
};

/**
 * Format a date for display in application forms
 * @param {string|Date} date - Date to format
 * @returns {string} Date formatted as YYYY-MM-DD for input[type="date"]
 */
const formatForDateInput = (date) => {
  if (!date) return '';
  
  try {
    const dateObj = new Date(date);
    return format(dateObj, 'yyyy-MM-dd');
  } catch (error) {
    console.error('Error formatting date for input:', error);
    return '';
  }
};

/**
 * Get a formatted date range display
 * @param {string|Date} startDate - Start date
 * @param {string|Date} endDate - End date
 * @returns {string} Formatted date range
 */
const formatDateRange = (startDate, endDate) => {
  if (!startDate || !endDate) return 'N/A';
  
  try {
    const startDateObj = new Date(startDate);
    const endDateObj = new Date(endDate);
    return `${format(startDateObj, 'PP')} - ${format(endDateObj, 'PP')}`;
  } catch (error) {
    console.error('Error formatting date range:', error);
    return 'Invalid date range';
  }
};

export default formatDate;

export {
  formatDateTime,
  formatRelativeTime,
  formatForDateInput,
  formatDateRange
};
